---播放宝物技能

---@class LBattleSkillActTreasureSkill
local LBattleSkillActTreasureSkill = classX("LBattleSkillActTreasureSkill", nil)

---@param player LBattleSkillPlayer
---@param effData LSkillEffectData
---@param playState LBattleSkillPlayState
function LBattleSkillActTreasureSkill.Execute(player,effData, playState)
    local obj = player:GetTargetAtkUnitView()
    local objTargetPos = obj:GetTargetPos()
    local effRes = effData.effRes --光效名字
    local playTime = effData.playTime --光效持续时间
    local dissipateTime = effData.dissipateTime --光效消散时间
    local offset = effData.effOffsetStart --偏移
    local _viewMgr = player:GetViewMgr()
    local _skillData = player:GetSkillData()
    local effTrans = viewMgr:GetEffectRootTrans()
    local pos = Vector3.zero
    if objTargetPos then
        pos = Vector3.New(objTargetPos.x + offset.x,objTargetPos.y + offset.y,objTargetPos.z + offset.z)
    else
        --[[		local curSide = obj:GetTeamIdx()
                local fastSide = curSide == BattleTeamSide.teamB and BattleTeamSide.teamA or BattleTeamSide.teamB
                local centerPos = viewMgr:GetFormationCenterPosition(fastSide):Clone()
                local targetX = fastSide == BattleTeamSide.teamA and -offset.x or offset.x
                pos = Vector3.New(centerPos.x + targetX,offset.y,0)]]
    end
    local effectCtrl = _viewMgr:GetEffectCtrl()
    local effect = effectCtrl:MakeBattleSkillEffectObj(effTrans, effRes, pos, LFightConst.DIRECTION_RIGHT, 0, playTime,dissipateTime)
    local para =
    {
        type = 1,
        isUpperLayer=  player:IsUpperLayer(),--player._isUpperLayer,
        scale = 1,
        skillId = _skillData:GetSkillRefId(),
        skin = _skillData:GetTreasureSkin(),
    }
    effect:SetEffectPara(para)
    effectCtrl:AddEffect(effect)
end

return LBattleSkillActTreasureSkill